-- ===========================
-- prim_* マスタ DDL + seed（小学生社会版）
-- Supabase SQL Editor で実行。既存アプリのテーブルとは prim_ 接頭辞で分離。
-- 読み取りは anon、書き込みは行わない想定（マスタは管理者がseedで投入）。
-- ===========================

create table if not exists prim_regions (
  id text primary key,
  name text not null,
  name_kana text not null,
  name_grade4 text not null,
  map_no int
);

create table if not exists prim_prefectures (
  id text primary key,
  name text not null,
  name_kana text not null,
  name_grade4 text not null,
  capital text not null,
  capital_kana text not null,
  capital_grade4 text not null,
  region_id text not null references prim_regions(id),
  map_no int not null,
  specialties jsonb not null default '[]',
  grade int
);

create table if not exists prim_wards (
  id text primary key,
  name text not null,
  name_kana text not null,
  name_grade4 text not null,
  map_no int not null
);

-- RLS: 読み取りのみ公開
alter table prim_regions enable row level security;
drop policy if exists "prim_regions_read" on prim_regions;
create policy "prim_regions_read" on prim_regions for select using (true);
alter table prim_prefectures enable row level security;
drop policy if exists "prim_prefectures_read" on prim_prefectures;
create policy "prim_prefectures_read" on prim_prefectures for select using (true);
alter table prim_wards enable row level security;
drop policy if exists "prim_wards_read" on prim_wards;
create policy "prim_wards_read" on prim_wards for select using (true);

